################################################################ Customer Segmentation with Unsupervised Learning############################################################################################################################### Business Problem################################################################ FLO wants to segment its customers and develop marketing strategies# based on these customer segments.## In this project, customer behaviors will be represented using meaningful# numerical features. Then, customers will be grouped based on behavioral# similarities by using unsupervised learning methods:## - K-Means Clustering# - Hierarchical Clustering## The final goal is to identify interpretable customer segments and support# data-driven marketing decisions.################################################################ Dataset Story################################################################ The dataset consists of historical shopping behavior of FLO customers# whose last purchases were made in 2020-2021 through OmniChannel.## OmniChannel means that customers purchased from both online and offline# channels.# Dataset:# 19,945 observations# 12 variables# Approximately 2.7 MB# master_id:# Unique customer ID# order_channel:# Shopping channel used by the customer such as Android, iOS, Desktop, Mobile# last_order_channel:# Channel of the customer's last purchase# first_order_date:# Customer's first purchase date# last_order_date:# Customer's last purchase date# last_order_date_online:# Customer's last online purchase date# last_order_date_offline:# Customer's last offline purchase date# order_num_total_ever_online:# Total number of online purchases made by the customer# order_num_total_ever_offline:# Total number of offline purchases made by the customer# customer_value_total_ever_offline:# Total amount paid by the customer in offline purchases# customer_value_total_ever_online:# Total amount paid by the customer in online purchases# interested_in_categories_12:# Categories the customer purchased from in the last 12 months################################################################ Tasks################################################################ TASK 1: Data Preparation#   Step 1: Read the flo_data_20K.csv dataset.#   Step 2: Select the variables to be used for customer segmentation.#           New variables such as tenure and recency can be created.# TASK 2: Customer Segmentation with K-Means#   Step 1: Standardize the variables.#   Step 2: Determine the optimum number of clusters.#   Step 3: Build the model and segment customers.#   Step 4: Analyze each segment statistically.# TASK 3: Customer Segmentation with Hierarchical Clustering#   Step 1: Determine the optimum number of clusters using the standardized dataframe from Task 2.#   Step 2: Build the model and segment customers.#   Step 3: Analyze each segment statistically.################################################################ Libraries and Settings###############################################################import warningswarnings.filterwarnings("ignore")import pandas as pdimport numpy as npimport datetime as dtimport matplotlib.pyplot as pltimport seaborn as snsimport osOUTPUT_DIR = "outputs"os.makedirs(OUTPUT_DIR, exist_ok=True)from scipy import statsfrom scipy.cluster.hierarchy import linkage, dendrogramfrom sklearn.preprocessing import StandardScalerfrom sklearn.cluster import KMeans, AgglomerativeClusteringfrom sklearn.metrics import silhouette_scorepd.set_option("display.max_columns", None)pd.set_option("display.max_rows", None)pd.set_option("display.float_format", lambda x: "%.2f" % x)pd.set_option("display.width", 1000)################################################################ TASK 1: Data Preparation############################################################################################################################### Step 1: Read the flo_data_20K.csv dataset.###############################################################df_ = pd.read_csv("flo_data_20k.csv")df = df_.copy()df.head()df.info()df.isnull().sum()df.describe().T################################################################ Step 2: Select the variables to be used for customer segmentation.# New variables such as tenure and recency can be created.################################################################ Convert date variables to datetime format.date_columns = df.columns[df.columns.str.contains("date")]df[date_columns] = df[date_columns].apply(pd.to_datetime)df.info()# Check the latest order date in the dataset.df["last_order_date"].max()# Since the latest order date is 2021-05-30,# the analysis date is selected as 2021-06-01.analysis_date = dt.datetime(2021, 6, 1)# Recency:# Number of days since the customer's last purchase.df["recency"] = (analysis_date - df["last_order_date"]).dt.days# Tenure:# Customer lifetime in days.df["tenure"] = (df["last_order_date"] - df["first_order_date"]).dt.days# Total number of purchases:# Combines online and offline purchase frequency.df["total_order_num"] = (    df["order_num_total_ever_online"] +    df["order_num_total_ever_offline"])# Total customer value:# Combines online and offline monetary value.df["total_customer_value"] = (    df["customer_value_total_ever_online"] +    df["customer_value_total_ever_offline"])# Average order value:# Represents average spending per order.df["average_order_value"] = (    df["total_customer_value"] / df["total_order_num"])# Select variables for clustering.model_df = df[    [        "order_num_total_ever_online",        "order_num_total_ever_offline",        "customer_value_total_ever_offline",        "customer_value_total_ever_online",        "total_order_num",        "total_customer_value",        "average_order_value",        "recency",        "tenure"    ]].copy()model_df.head()################################################################ TASK 2: Customer Segmentation with K-Means############################################################################################################################### Step 1: Standardize the variables.###############################################################def check_skew(dataframe, column):    skew = stats.skew(dataframe[column])    skewtest = stats.skewtest(dataframe[column])    plt.title("Distribution of " + column)    sns.histplot(dataframe[column], kde=True)    print(        "{} | Skew: {:.4f} | Skewtest Statistic: {:.4f} | p-value: {:.4f}".format(            column,            skew,            skewtest.statistic,            skewtest.pvalue        )    )# Distribution check before transformation.plt.figure(figsize=(12, 18))for index, col in enumerate(model_df.columns, 1):    plt.subplot(len(model_df.columns), 1, index)    check_skew(model_df, col)plt.tight_layout()plt.savefig(os.path.join(OUTPUT_DIR, "before_transform.png"), format="png", dpi=300, bbox_inches="tight")plt.show()# Log transformation:# Customer transaction and monetary variables are generally right-skewed.# np.log1p is used because it safely handles zero values.for col in model_df.columns:    model_df[col] = np.log1p(model_df[col])model_df.head()# Distribution check after transformation.plt.figure(figsize=(12, 18))for index, col in enumerate(model_df.columns, 1):    plt.subplot(len(model_df.columns), 1, index)    check_skew(model_df, col)plt.tight_layout()plt.savefig(os.path.join(OUTPUT_DIR, "after_transform.png"), format="png", dpi=300, bbox_inches="tight")plt.show()# Standardization:# StandardScaler is preferred because K-Means and Hierarchical Clustering# are distance-based algorithms.scaler = StandardScaler()model_scaling = scaler.fit_transform(model_df)model_df = pd.DataFrame(model_scaling, columns=model_df.columns)model_df.head()################################################################ Step 2: Determine the optimum number of clusters.################################################################ Manual Elbow Method:# WCSS/Inertia is calculated for different k values.# This method is preferred because it does not require an extra dependency.wcss = []for k in range(2, 20):    kmeans = KMeans(n_clusters=k, random_state=42, n_init=10)    kmeans.fit(model_df)    wcss.append(kmeans.inertia_)plt.figure(figsize=(10, 6))plt.plot(range(2, 20), wcss, marker="o")plt.xlabel("Number of Clusters")plt.ylabel("WCSS")plt.title("Elbow Method")plt.savefig(os.path.join(OUTPUT_DIR, "elbow_method.png"), format="png", dpi=300, bbox_inches="tight")plt.show()# Silhouette Score:# Used as an additional validation metric for cluster quality.silhouette_scores = {}for k in range(2, 11):    kmeans_model = KMeans(n_clusters=k, random_state=42, n_init=10)    labels = kmeans_model.fit_predict(model_df)    score = silhouette_score(model_df, labels)    silhouette_scores[k] = score    print("k =", k, "| Silhouette Score:", round(score, 4))# Final cluster number:## Although k=2 gives the highest silhouette score, it produces overly broad# customer groups and is not sufficiently actionable for marketing strategy.## In customer segmentation projects, the final cluster number should be selected# not only by a mathematical metric but also by business interpretability.## Based on the elbow plot, silhouette scores, and the need for more granular# marketing segments, k=7 is selected.optimal_k = 7################################################################ Step 3: Build the model and segment customers.###############################################################k_means = KMeans(    n_clusters=optimal_k,    random_state=42,    n_init=10).fit(model_df)segments = k_means.labels_final_df = df[    [        "master_id",        "order_num_total_ever_online",        "order_num_total_ever_offline",        "customer_value_total_ever_offline",        "customer_value_total_ever_online",        "total_order_num",        "total_customer_value",        "average_order_value",        "recency",        "tenure"    ]].copy()final_df["segment"] = segmentsfinal_df.head()final_df["segment"].value_counts()################################################################ Step 4: Analyze each segment statistically.###############################################################kmeans_segment_analysis = final_df.groupby("segment").agg({    "order_num_total_ever_online": ["mean", "min", "max"],    "order_num_total_ever_offline": ["mean", "min", "max"],    "customer_value_total_ever_offline": ["mean", "min", "max"],    "customer_value_total_ever_online": ["mean", "min", "max"],    "total_order_num": ["mean", "min", "max"],    "total_customer_value": ["mean", "min", "max"],    "average_order_value": ["mean", "min", "max"],    "recency": ["mean", "min", "max"],    "tenure": ["mean", "min", "max", "count"]})print(kmeans_segment_analysis)# Business-oriented summary table:kmeans_business_summary = final_df.groupby("segment").agg({    "total_customer_value": "mean",    "total_order_num": "mean",    "average_order_value": "mean",    "recency": "mean",    "tenure": "mean"}).sort_values("total_customer_value", ascending=False)print(kmeans_business_summary)# Segment interpretation based on the current K-Means output:## Segment 2:# Highest total_customer_value and highest total_order_num.# This segment represents high-value and highly engaged customers.# Recommended strategy: VIP campaigns, loyalty programs, premium offers.## Segment 3:# Second highest total_customer_value with strong offline and online behavior.# This segment represents valuable multi-channel customers.# Recommended strategy: OmniChannel campaigns, personalized product recommendations.## Segment 6:# Medium-high value customers with relatively good purchase frequency.# Recommended strategy: retention campaigns and category-based offers.## Segment 5:# High average_order_value but lower total_order_num.# These customers spend more per order but purchase less frequently.# Recommended strategy: frequency-increasing campaigns and reminder campaigns.## Segment 0:# Moderate frequency and moderate value customers.# Recommended strategy: basket-size increasing campaigns and cross-selling.## Segment 1:# Low tenure and relatively low total_order_num.# These may be newer customers.# Recommended strategy: onboarding campaigns and first-loyalty incentives.## Segment 4:# Lowest total_customer_value and low average_order_value.# Recommended strategy: controlled reactivation campaigns with low marketing budget.################################################################ TASK 3: Customer Segmentation with Hierarchical Clustering############################################################################################################################### Step 1: Determine the optimum number of clusters using the# standardized dataframe from Task 2.###############################################################hc_ward = linkage(model_df, method="ward")plt.figure(figsize=(10, 6))plt.title("Hierarchical Clustering Dendrogram")plt.xlabel("Customers")plt.ylabel("Euclidean Distance")dend = dendrogram(    hc_ward,    truncate_mode="lastp",    p=10,    show_contracted=True,    leaf_font_size=10)plt.axhline(y=25, color="r", linestyle="--")plt.savefig(os.path.join(OUTPUT_DIR, "hierarchical_dendrogram.png"), format="png", dpi=300, bbox_inches="tight")plt.show()# Select the number of clusters according to the dendrogram.# To make both models comparable, the same optimal_k value is used here.# If the dendrogram clearly suggests a different number, update it manually.hc_cluster_count = optimal_k################################################################ Step 2: Build the model and segment customers.###############################################################hc = AgglomerativeClustering(    n_clusters=hc_cluster_count,    linkage="ward")segments = hc.fit_predict(model_df)final_df_hc = df[    [        "master_id",        "order_num_total_ever_online",        "order_num_total_ever_offline",        "customer_value_total_ever_offline",        "customer_value_total_ever_online",        "total_order_num",        "total_customer_value",        "average_order_value",        "recency",        "tenure"    ]].copy()final_df_hc["segment"] = segmentsfinal_df_hc.head()final_df_hc["segment"].value_counts()################################################################ Step 3: Analyze each segment statistically.###############################################################hc_segment_analysis = final_df_hc.groupby("segment").agg({    "order_num_total_ever_online": ["mean", "min", "max"],    "order_num_total_ever_offline": ["mean", "min", "max"],    "customer_value_total_ever_offline": ["mean", "min", "max"],    "customer_value_total_ever_online": ["mean", "min", "max"],    "total_order_num": ["mean", "min", "max"],    "total_customer_value": ["mean", "min", "max"],    "average_order_value": ["mean", "min", "max"],    "recency": ["mean", "min", "max"],    "tenure": ["mean", "min", "max", "count"]})print(hc_segment_analysis)# Business-oriented summary table:hc_business_summary = final_df_hc.groupby("segment").agg({    "total_customer_value": "mean",    "total_order_num": "mean",    "average_order_value": "mean",    "recency": "mean",    "tenure": "mean"}).sort_values("total_customer_value", ascending=False)print(hc_business_summary)# Segment interpretation based on the current Hierarchical Clustering output:## Segment 3:# Highest total_customer_value and total_order_num.# This segment represents high-value loyal customers.## Segment 5:# High customer value and strong purchase frequency.# This segment represents valuable customers with strong offline behavior.## Segment 4:# Medium-high value customers.# This group can be targeted with retention and personalized campaigns.## Segment 0:# High average_order_value but lower frequency.# This group can be targeted with frequency-increasing campaigns.## Segment 2:# Moderate value and moderate frequency customers.# This group has growth potential.## Segment 1:# Lower value customers with moderate offline behavior.# This group can be targeted with selective campaigns.## Segment 6:# Lowest total_customer_value and low purchase frequency.# This group should be targeted carefully due to lower expected return.# K-Means vs Hierarchical Clustering Comparison:## This comparison table shows how customer assignments differ between# the two clustering approaches. It helps evaluate whether both methods# produce broadly consistent segmentation patterns.comparison_table = pd.crosstab(    final_df["segment"],    final_df_hc["segment"])print(comparison_table)# Final business note:## K-Means is generally more practical and scalable for customer segmentation.# Hierarchical Clustering is useful for understanding nested customer structures# and validating the segmentation tendency.## Since K-Means provides clear and actionable customer groups in this project,# it can be used as the primary segmentation model for marketing strategy.